package metodos.primitivos.tipos.parametros.domain;public class Calculadora {    public int somaNums(int num1, int num2){        return num1 + num2;    }    public int subtracaoNums(int num1, int num2){        return num1 - num2;    }    public int multiplyNums(int num1, int num2){        return num1 * num2;    }    public double divisaoNums(int num1, int num2){        if (num2 == 0)            System.out.println("O divisor é zero");        return (double) num1  / num2;    }    public void alternarNumeros(int num1, int num2){        num1 = 99;        num2 = 33;        System.out.println("Números alterados com sucesso!");        System.out.println("Num1: "+num1 + " Num2: "+num2);    }}